+    #[test]
+    fn get_all_frames_after_eviction() {
+        let mut tt = TimeTravel::new(3);
+        let mut buf = Buffer::new(3, 1);
+
+        // Record 5 frames: A, B, C, D, E
+        for i in 0..5u64 {
+            buf.set(0, 0, Cell::from_char(char::from(b'A' + i as u8)));
+            tt.record(&buf, make_metadata(i));
+        }
